#include "timer_scheduler.h"
#define MAX_TIMERS 16
static struct{uint32_t interval;timer_cb cb;unsigned long last;bool active;}_timers[MAX_TIMERS];
static uint8_t _count=0;
void scheduler_setup(){for(int i=0;i<MAX_TIMERS;i++)_timers[i].active=false;Serial.println("[sched] OK");}
uint8_t scheduler_add(uint32_t ms,timer_cb cb){if(_count>=MAX_TIMERS)return 255;uint8_t id=_count++;_timers[id]={ms,cb,millis(),true};return id;}
void scheduler_remove(uint8_t id){if(id<MAX_TIMERS)_timers[id].active=false;}
void scheduler_loop(){unsigned long now=millis();for(int i=0;i<_count;i++){if(_timers[i].active&&now-_timers[i].last>=_timers[i].interval){_timers[i].last=now;_timers[i].cb();}}}
